#include "conv_transposed_3d_square_input_square_kernel_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 128 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 64;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvTransposed3dSquareInputSquareKernelCustomTilingData tiling;

    const gert::StorageShape *xShape = context->GetInputShape(0);
    const gert::StorageShape *wShape = context->GetInputShape(1);
    const auto &xOrigin = xShape->GetOriginShape();
    const auto &wOrigin = wShape->GetOriginShape();

    const uint32_t n   = xOrigin.GetDim(0);
    const uint32_t cIn = xOrigin.GetDim(1);
    const uint32_t dIn = xOrigin.GetDim(2);
    const uint32_t hIn = xOrigin.GetDim(3);
    const uint32_t wIn = xOrigin.GetDim(4);

    const uint32_t cOut = wOrigin.GetDim(1);
    const uint32_t kD   = wOrigin.GetDim(2);
    const uint32_t kH   = wOrigin.GetDim(3);
    const uint32_t kW   = wOrigin.GetDim(4);

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int64_t *stride = attrs->GetAttrPointer<int64_t>(0);
    const int64_t *padding = attrs->GetAttrPointer<int64_t>(1);
    const int64_t *output_padding = attrs->GetAttrPointer<int64_t>(2);
    const int64_t groups = attrs->GetAttrPointer<int64_t>(3)[0];
    const int64_t *dilation = attrs->GetAttrPointer<int64_t>(4);

    uint32_t dOut = (dIn - 1) * stride[0] + dilation[0] * (kD - 1) + output_padding[0] + 1;
    uint32_t hOut = (hIn - 1) * stride[1] + dilation[1] * (kH - 1) + output_padding[1] + 1;
    uint32_t wOut = (wIn - 1) * stride[2] + dilation[2] * (kW - 1) + output_padding[2] + 1;

    const uint32_t totalLength = n * cOut * dOut * hOut * wOut;

    uint32_t maxTile = UB_BUDGET_BYTES / sizeof(float);
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;

    uint32_t tileLen = maxTile;
    if (totalLength < tileLen) {
        tileLen = AlignDown(totalLength, ALIGN_ELEMS);
        if (tileLen == 0) tileLen = totalLength;
    }

    uint32_t numTiles = CeilDiv(totalLength, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_n(n);
    tiling.set_cOut(cOut);
    tiling.set_dOut(dOut);
    tiling.set_hOut(hOut);
    tiling.set_wOut(wOut);
    tiling.set_cIn(cIn);
    tiling.set_kD(kD);
    tiling.set_kH(kH);
    tiling.set_kW(kW);
    tiling.set_dIn(dIn);
    tiling.set_hIn(hIn);
    tiling.set_wIn(wIn);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

